import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // 1. Fetch all projects from the backend on component mount
  const fetchAllProjects = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setProjects(res.data);
      setLoading(false);
    } catch (err) {
      setError("❌ Failed to load data. Please ensure the backend server is running.");
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllProjects();
  }, []);

  // 2. Function for clients to send revision/change requests
  const handleRevisionRequest = async (id) => {
    const revisionMsg = document.getElementById(`rev-${id}`).value;
    if (!revisionMsg.trim()) return alert("Please describe the changes you need!");

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        revisionsRequested: revisionMsg
      });
      alert("✅ Your revision request has been sent successfully!");
      document.getElementById(`rev-${id}`).value = ""; // Clear input
      fetchAllProjects(); // Refresh dashboard to show the new request
    } catch (err) {
      alert("❌ Failed to send request. Please try again later.");
    }
  };

  return (
    <div className="container-fluid py-5 mt-4 px-lg-5">
      <div className="text-center mb-5">
        <h2 className="fw-bold text-primary">Live Project Tracker</h2>
        <p className="text-muted">Real-time status report of all our active projects.</p>
      </div>

      {loading ? (
        <div className="text-center py-5">
          <div className="spinner-border text-primary" role="status"></div>
          <p className="mt-2">Loading projects...</p>
        </div>
      ) : error ? (
        <div className="alert alert-danger text-center shadow-sm">{error}</div>
      ) : (
        <div className="row g-4">
          {projects.length > 0 ? projects.map((proj) => (
            <div className="col-12 mb-4" key={proj._id}>
              <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
                {/* Card Header */}
                <div className="card-header bg-dark text-white p-3 d-flex justify-content-between align-items-center">
                  <h5 className="mb-0 fw-bold">{proj.fullName} - <small className="text-warning">{proj.serviceType}</small></h5>
                  <span className={`badge px-3 py-2 ${proj.status === 'Completed' ? 'bg-success' : 'bg-warning text-dark'}`}>
                    {proj.status}
                  </span>
                </div>

                <div className="card-body p-4 bg-white">
                  <div className="row align-items-center">
                    {/* 1. Work Progress Section */}
                    <div className="col-md-4 mb-3 mb-md-0">
                      <label className="fw-bold small mb-2 text-secondary text-uppercase">Work Progress</label>
                      <div className="d-flex align-items-center gap-2">
                        <div className="progress flex-grow-1 shadow-sm" style={{ height: '12px' }}>
                          <div 
                            className={`progress-bar progress-bar-striped progress-bar-animated ${proj.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                            style={{ width: `${proj.progress}%` }}
                          ></div>
                        </div>
                        <span className="fw-bold text-primary">{proj.progress}%</span>
                      </div>
                    </div>

                    {/* 2. Payment Summary Section */}
                    <div className="col-md-4 mb-3 mb-md-0 border-start border-end px-4">
                      <label className="fw-bold small mb-2 text-secondary text-uppercase">Payment Summary</label>
                      <div className="d-flex justify-content-between mb-1">
                        <span className="small text-muted">Total Budget:</span>
                        <span className="fw-bold text-dark">₹{proj.totalBudget}</span>
                      </div>
                      <div className="d-flex justify-content-between mb-1">
                        <span className="small text-muted">Advance Paid:</span>
                        <span className="fw-bold text-success">₹{proj.advancePaid}</span>
                      </div>
                      <hr className="my-1" />
                      <div className="d-flex justify-content-between">
                        <span className="small fw-bold">Remaining Balance:</span>
                        <span className="fw-bold text-danger">₹{proj.totalBudget - proj.advancePaid}</span>
                      </div>
                    </div>

                    {/* 3. Revision/Changes Section */}
                    <div className="col-md-4">
                      <label className="fw-bold small mb-2 text-primary text-uppercase">Request Changes / Revisions</label>
                      <div className="input-group">
                        <input 
                          type="text" id={`rev-${proj._id}`} 
                          className="form-control form-control-sm" 
                          placeholder="Type changes you need..." 
                        />
                        <button 
                          className="btn btn-primary btn-sm fw-bold px-3" 
                          onClick={() => handleRevisionRequest(proj._id)}
                        >
                          Send
                        </button>
                      </div>
                      {proj.revisionsRequested && (
                        <div className="mt-2 p-2 bg-light rounded" style={{fontSize: '12px'}}>
                          <strong className="text-dark">Current Request:</strong> <span className="text-muted">{proj.revisionsRequested}</span>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )) : (
            <div className="text-center py-5 text-muted">
              <h5>No active projects found.</h5>
            </div>
          )}
        </div>
      )}

      <div className="mt-5 text-center small text-muted">
        <i className="fas fa-info-circle me-1"></i> This data is updated in real-time by the Administrator.
      </div>
    </div>
  );
}

export default ClientDashboard;
